import React, { useState, useEffect } from "react";
import axios from "axios";
import ReactPlayer from "react-player";
import { SiYoutubeshorts } from "react-icons/si";
import { FiArrowDownCircle } from "react-icons/fi";
import Header from "../components/common/Header";
import Footer from "../components/common/Footer";
import Navbar from "../components/common/Navbar";
import logo from "../assets/cxotv-header-logo.jpg";
const Shorts = () => {
  const [shortsData, setShortsData] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const [visibleCount, setVisibleCount] = useState(12); // Number of items initially visible
  const increment = 12; // Number of items to load on each click

  useEffect(() => {
    const fetchShorts = async () => {
      try {
        const response = await axios.get(`${process.env.REACT_APP_UPLOAD_URL}/api/shortss?populate=*&sort=publishedAt:DESC&pagination[limit]=90`);
        setShortsData(response.data.data);
        setIsLoading(false);
      } catch (error) {
        setError(error.message);
        setIsLoading(false);
      }
    };

    fetchShorts();
  }, []);

  const loadMore = () => {
    if (visibleCount < shortsData.length) {
      setVisibleCount((prevCount) => prevCount + increment);
    }
  };

  if (isLoading) {
    return <div>Loading...</div>;
  }

  if (error) {
    return <div>Error: {error}</div>;
  }

  return (
    <>
      <div className="">
        <Header logo={logo}></Header>
      </div>
      <div>
        <Navbar></Navbar>
      </div>
      <div className="lg:px-32 px-4 py-4">
        <div className="flex items-center justify-start py-2">
          <SiYoutubeshorts size={32} color="#FF0000" />
          <h1 className="text-2xl font-bold ml-2 mb-4">Shorts</h1>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-10">
          {shortsData.slice(0, visibleCount).map((short) => (
            <div key={short.id} className="max-w-lg">
              <div className="bg-gray-900 rounded-lg overflow-hidden shadow-md">
                <ReactPlayer
                  url={short.attributes.ShortsUrl}
                  controls
                  width="100%"
                  height="450px"
                />
              </div>
            </div>
          ))}
        </div>
        {visibleCount < shortsData.length && (
          <div className="flex justify-center mt-6">
          <button
              className="bg-blue-500 text-white px-4 py-2 rounded flex items-center"
              onClick={loadMore}
            >
              <FiArrowDownCircle className="mr-2" />
              Load More
            </button>
          </div>
        )}
      </div>
      <div className="mt-6">
        <Footer />
      </div>
    </>
  );
};

export default Shorts;
